const now = new Date();
const oneDay = 24 * 60 * 60 * 1000; 

for (const item of $input.all()) {
  const data = item.json;
  const reviews = data.reviews || [];
  let week1 = 0, week2 = 0, week3 = 0, week4 = 0, aMonthAgo = 0;

  reviews.forEach(review => {
    if (!review.publishedAtDate) return;
    const reviewDate = new Date(review.publishedAtDate);
    const diffDays = Math.floor((now - reviewDate) / oneDay);
    if (diffDays <= 7) week1++;
    else if (diffDays <= 14) week2++;
    else if (diffDays <= 21) week3++;
    else if (diffDays <= 30) week4++;
    else if (diffDays <= 60) aMonthAgo++;
  });

  const urls = data.imageUrls || [];
  let ownerImgCount = 0;
  let customerImgCount = 0;
  urls.forEach(url => {
    if (url.includes('/p/') || url.includes('/proxy/')) {
      ownerImgCount++;
    } else if (url.includes('/gps-cs-s/')) {
      customerImgCount++;
    }
  });

  const hasName = !!data.title;
  const hasAddress = !!data.address;
  const hasPhone = !!data.phone;
  const hasWebsite = !!data.website;
  const websiteStr = (data.website || "").toLowerCase();
  const hasFB = websiteStr.includes('facebook.com');
  const hasIG = websiteStr.includes('instagram.com');
  const totalCategories = [hasName, hasAddress, hasPhone, hasWebsite, hasFB, hasIG].filter(Boolean).length;

  item.json.combined_stats = {
    reviews: {
      week1, week2, week3, week4, month_ago_label: aMonthAgo,
      total_recent_reviews: week1 + week2 + week3 + week4 + aMonthAgo
    },
    images: {
      owner_count: ownerImgCount,
      customer_count: customerImgCount,
      total_images_scraped: urls.length
    },
    napw: totalCategories
  };
}
return $input.all();

const items = $input.all();
const now = new Date();
const fourWeeksAgo = new Date(now);
fourWeeksAgo.setDate(now.getDate() - 28);
function getWeekNumber(postDate) {
  const daysAgo = (now - postDate) / (1000 * 60 * 60 * 24);
  if (daysAgo <= 7) return 1;
  if (daysAgo <= 14) return 2;
  if (daysAgo <= 21) return 3;
  return 4;
}
function getTimeWeight(week) {
  const weights = { 1: 1.00, 2: 0.75, 3: 0.50, 4: 0.25 };
  return weights[week];
}
const pageData = items[0]?.json || {};
const followers = pageData.followersCount || 0;
const isVerified = pageData.verified || false;
const allPosts = items.flatMap(item => item.json.latestPosts || []);
const filteredPosts = allPosts.filter(post => {
  const postDate = new Date(post.timestamp);
  return postDate >= fourWeeksAgo && postDate <= now;
});
const weeks = { 1: [], 2: [], 3: [], 4: [] };
filteredPosts.forEach(post => {
  const postDate = new Date(post.timestamp);
  const week = getWeekNumber(postDate);
  const likes = post.likesCount || 0;
  weeks[week].push(likes);
});
const weekStats = {};
[1, 2, 3, 4].forEach(w => {
  const count = weeks[w].length;
  const weight = getTimeWeight(w);
  const weightedCount = count * weight;
  const rawLikesSum = weeks[w].reduce((sum, l) => sum + l, 0);
  const avgLikes = count > 0 ? Math.round((rawLikesSum / count) * 100) / 100 : 0;
  weekStats[`week${w}Count`] = count;
  weekStats[`week${w}Weight`] = weight;
  weekStats[`week${w}WeightedCount`] = Math.round(weightedCount * 100) / 100;
  weekStats[`week${w}TotalLikes`] = rawLikesSum;
  weekStats[`week${w}AverageLikes`] = avgLikes;
});
const totalPosts = filteredPosts.length;
const totalLikes = filteredPosts.reduce((sum, post) => sum + (post.likesCount || 0), 0);
const averageLikes = totalPosts > 0 ? Math.round((totalLikes / totalPosts) * 100) / 100 : 0;
const totalWeightedCount = [1, 2, 3, 4].reduce((sum, w) => sum + weekStats[`week${w}WeightedCount`], 0);
return [{ json: { ...weekStats, totalPostsInRange: totalPosts, totalWeightedCount: Math.round(totalWeightedCount * 100) / 100, totalLikes, averageLikes, followers, isVerified, rangeStart: fourWeeksAgo.toISOString().split('T')[0], rangeEnd: now.toISOString().split('T')[0] } }];

